// ─── Filter posts that are due NOW (CST timezone) ───
// The portal schedules posts in CST (UTC-6).
// Only returns posts whose date+time has arrived.

const items = $input.all();
if (!items || items.length === 0) return [];

const now = new Date();
const cstOffset = -6 * 60;
const utcMs = now.getTime() + now.getTimezoneOffset() * 60000;
const cstNow = new Date(utcMs + cstOffset * 60000);
const nowDate = cstNow.toISOString().split('T')[0];
const nowHH = String(cstNow.getHours()).padStart(2, '0');
const nowMM = String(cstNow.getMinutes()).padStart(2, '0');
const nowTime = `${nowHH}:${nowMM}`;

const due = items.filter(item => {
  const d = item.json.scheduled_date;
  const t = (item.json.scheduled_time || '').substring(0, 5);
  if (!d || !t) return false;
  if (d < nowDate) return true;
  if (d === nowDate && t <= nowTime) return true;
  return false;
});

return due;

// ═══════════════════════════════════════════════════════
// Ten80Ten Auto-Publisher — Platform Posting Engine
// ═══════════════════════════════════════════════════════
//
// SETUP: Replace the placeholders below with your real credentials.
//
// Facebook + Instagram:
//   1. Create a Meta App at developers.facebook.com
//   2. Add Facebook Login + Pages API + Instagram Graph API
//   3. Generate a long-lived Page Access Token
//   4. Get your FB Page ID and IG Business Account ID
//
// LinkedIn:
//   1. Create a LinkedIn App at linkedin.com/developers
//   2. Request 'w_member_social' or 'w_organization_social' scope
//   3. Generate an OAuth2 access token
//   4. Get your Organization URN
//
// ═══════════════════════════════════════════════════════

// ─── CREDENTIALS (edit these) ───
const META_ACCESS_TOKEN = 'YOUR_META_PAGE_ACCESS_TOKEN';
const FB_PAGE_ID         = 'YOUR_FACEBOOK_PAGE_ID';
const IG_USER_ID         = 'YOUR_INSTAGRAM_BUSINESS_ACCOUNT_ID';
const LI_ACCESS_TOKEN    = 'YOUR_LINKEDIN_ACCESS_TOKEN';
const LI_ORG_URN         = 'urn:li:organization:YOUR_ORG_ID';
// ─────────────────────────────────

const _http = this.helpers.httpRequest.bind(this.helpers);

const post = $input.item.json;
const platforms = Array.isArray(post.platforms) ? post.platforms : [];
const caption = post.caption || '';
const contentType = post.content_type || 'image';

// Parse source_vault (may be string or object)
let vault = post.source_vault || {};
if (typeof vault === 'string') {
  try { vault = JSON.parse(vault); } catch { vault = {}; }
}
const rawFiles = vault.rawFiles || [];
const master = rawFiles.find(f => f.usageType === 'master') || rawFiles[0];

if (!master) {
  return { json: { postId: post.id, title: post.title, error: 'No content file in source vault', results: [] } };
}

// Resolve Google Drive URL to direct download format
function driveUrl(url) {
  if (!url) return url;
  // If it's a portal-relative URL, we can't use it externally
  if (url.startsWith('/')) return null;
  // Convert Drive view links to direct download
  if (url.includes('drive.google.com')) {
    const m = url.match(/\/d\/([a-zA-Z0-9_-]+)/) || url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
    if (m) return `https://drive.google.com/uc?export=download&id=${m[1]}`;
  }
  return url;
}

const fileUrl = driveUrl(master.url);
if (!fileUrl) {
  return { json: { postId: post.id, title: post.title, error: 'File URL is not publicly accessible', results: [] } };
}

const results = [];

// ─── FACEBOOK ───
async function postToFacebook() {
  if (contentType === 'video' || contentType === 'reel') {
    const res = await _http({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${FB_PAGE_ID}/videos`,
      qs: { file_url: fileUrl, description: caption, access_token: META_ACCESS_TOKEN },
    });
    return { platform: 'facebook', success: true, id: res.id };
  }
  // Image or carousel (FB treats carousel as album — post first image)
  const res = await _http({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${FB_PAGE_ID}/photos`,
    qs: { url: fileUrl, message: caption, access_token: META_ACCESS_TOKEN },
  });
  return { platform: 'facebook', success: true, id: res.id || res.post_id };
}

// ─── INSTAGRAM ───
async function postToInstagram() {
  // Carousel with multiple files
  if (contentType === 'carousel' && rawFiles.length > 1) {
    const childIds = [];
    for (const file of rawFiles) {
      const url = driveUrl(file.url);
      if (!url) continue;
      const child = await _http({
        method: 'POST',
        url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media`,
        qs: { image_url: url, is_carousel_item: true, access_token: META_ACCESS_TOKEN },
      });
      childIds.push(child.id);
    }
    const container = await _http({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media`,
      qs: { media_type: 'CAROUSEL', children: childIds.join(','), caption, access_token: META_ACCESS_TOKEN },
    });
    // Poll until container is ready
    await waitForContainer(container.id);
    const pub = await _http({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media_publish`,
      qs: { creation_id: container.id, access_token: META_ACCESS_TOKEN },
    });
    return { platform: 'instagram', success: true, id: pub.id };
  }

  // Video / Reel
  if (contentType === 'video' || contentType === 'reel') {
    const container = await _http({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media`,
      qs: { media_type: 'REELS', video_url: fileUrl, caption, access_token: META_ACCESS_TOKEN },
    });
    await waitForContainer(container.id);
    const pub = await _http({
      method: 'POST',
      url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media_publish`,
      qs: { creation_id: container.id, access_token: META_ACCESS_TOKEN },
    });
    return { platform: 'instagram', success: true, id: pub.id };
  }

  // Single image
  const container = await _http({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media`,
    qs: { image_url: fileUrl, caption, access_token: META_ACCESS_TOKEN },
  });
  await waitForContainer(container.id);
  const pub = await _http({
    method: 'POST',
    url: `https://graph.facebook.com/v21.0/${IG_USER_ID}/media_publish`,
    qs: { creation_id: container.id, access_token: META_ACCESS_TOKEN },
  });
  return { platform: 'instagram', success: true, id: pub.id };
}

// Poll IG container status until FINISHED (required for video/carousel)
async function waitForContainer(containerId) {
  for (let i = 0; i < 30; i++) {
    await new Promise(r => setTimeout(r, 5000));
    const check = await _http({
      method: 'GET',
      url: `https://graph.facebook.com/v21.0/${containerId}`,
      qs: { fields: 'status_code', access_token: META_ACCESS_TOKEN },
    });
    if (check.status_code === 'FINISHED') return;
    if (check.status_code === 'ERROR') throw new Error(`IG container failed: ${JSON.stringify(check)}`);
  }
  throw new Error('IG container processing timed out after 150s');
}

// ─── LINKEDIN ───
async function postToLinkedin() {
  // Step 1: Register image upload
  const register = await _http({
    method: 'POST',
    url: 'https://api.linkedin.com/v2/assets?action=registerUpload',
    headers: { Authorization: `Bearer ${LI_ACCESS_TOKEN}`, 'Content-Type': 'application/json' },
    body: {
      registerUploadRequest: {
        recipes: ['urn:li:digitalmediaRecipe:feedshare-image'],
        owner: LI_ORG_URN,
        serviceRelationships: [{ relationshipType: 'OWNER', identifier: 'urn:li:userGeneratedContent' }],
      },
    },
  });

  const uploadUrl = register.value?.uploadMechanism?.['com.linkedin.digitalmedia.uploading.MediaUploadHttpRequest']?.uploadUrl;
  const asset = register.value?.asset;
  if (!uploadUrl || !asset) throw new Error('LinkedIn upload registration failed');

  // Step 2: Download file from Drive and upload to LinkedIn
  const fileData = await _http({ method: 'GET', url: fileUrl, encoding: 'arraybuffer' });
  await _http({
    method: 'PUT',
    url: uploadUrl,
    headers: { Authorization: `Bearer ${LI_ACCESS_TOKEN}` },
    body: fileData,
  });

  // Step 3: Create post
  const postRes = await _http({
    method: 'POST',
    url: 'https://api.linkedin.com/v2/ugcPosts',
    headers: { Authorization: `Bearer ${LI_ACCESS_TOKEN}`, 'Content-Type': 'application/json' },
    body: {
      author: LI_ORG_URN,
      lifecycleState: 'PUBLISHED',
      specificContent: {
        'com.linkedin.ugc.ShareContent': {
          shareCommentary: { text: caption },
          shareMediaCategory: 'IMAGE',
          media: [{ status: 'READY', media: asset }],
        },
      },
      visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC' },
    },
  });
  return { platform: 'linkedin', success: true, id: postRes.id };
}

// ─── EXECUTE ───
for (const platform of platforms) {
  try {
    switch (platform) {
      case 'facebook': results.push(await postToFacebook()); break;
      case 'instagram': results.push(await postToInstagram()); break;
      case 'linkedin': results.push(await postToLinkedin()); break;
      case 'x':
      case 'youtube':
      case 'tiktok':
        results.push({ platform, success: false, error: `${platform} not configured. Post manually.` });
        break;
      default:
        results.push({ platform, success: false, error: `Unknown platform: ${platform}` });
    }
  } catch (err) {
    results.push({ platform, success: false, error: err.message || String(err) });
  }
}

const succeeded = results.filter(r => r.success).map(r => r.platform);
const failed = results.filter(r => !r.success);

return {
  json: {
    postId: post.id,
    title: post.title,
    publishedAt: new Date().toISOString(),
    results,
    succeededPlatforms: succeeded,
    failedPlatforms: failed,
    summary: succeeded.length > 0
      ? `Published to ${succeeded.join(', ')}${failed.length > 0 ? `. Failed: ${failed.map(f => f.platform + ' (' + f.error + ')').join(', ')}` : ''}`
      : `All platforms failed: ${failed.map(f => f.platform + ' (' + f.error + ')').join(', ')}`,
  },
};
